// Import web3.js or ethers.js
const Web3 = require('web3');
const ethers = require('ethers');

// Define wallet configuration with private keys
const privateKey = 'your_private_key';
const address = 'your_wallet_address';

// Connect to Ethereum node
const web3 = new Web3('your_ethereum_node_url');

// Send ETH
const sendETH = async (toAddress, amount) => {
  const transaction = {
    from: address,
    to: toAddress,
    value: web3.utils.toWei(amount, 'ether'),
  };

  const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
  await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
};

// Interact with smart contract
const contractAddress = 'your_smart_contract_address';
const abi = ['your_smart_contract_abi'];

const contract = new web3.eth.Contract(abi, contractAddress);

const interactWithContract = async (functionName, ...args) => {
  const data = contract.methods[functionName](...args).encodeABI();
  const transaction = {
    from: address,
    to: contractAddress,
    data: data,
  };

  const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
  await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
};